proof fn phi_1_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.implies(q).satisfied_by(ex),
        p.satisfied_by(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_2_implies_apply_with_always_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        always(p.implies(q)).satisfied_by(ex),
        always(p).satisfied_by(ex),
    ensures
        always(q).satisfied_by(ex),
{
    implies_apply_with_always::<int>(ex, p, q);
}

proof fn phi_3_execution_equality_intensional_bridge(ex1: Execution<int>, ex2: Execution<int>)
    requires
        forall |i: nat| #[trigger] (ex1.nat_to_state)(i) == (ex2.nat_to_state)(i),
    ensures
        ex1 == ex2,
{
    execution_equality::<int>(ex1, ex2);
}
